import { getPermissionsCacheEntry } from '@linm-soft-org/linm-web-common-components';
import { isPermissionsLocalModeActive } from '../dev/isPermissionsLocalMode';

export function readCachedPermissionCodes(): string[] {
  const payload = getPermissionsCacheEntry()?.payload;
  const codes = payload?.permissionCodes;
  if (!Array.isArray(codes)) return [];
  return codes.filter((c): c is string => typeof c === 'string' && c.length > 0);
}

export function hasPermissionCode(code: string): boolean {
  if (isPermissionsLocalModeActive()) return true;
  const target = code.trim();
  if (!target) return false;
  return readCachedPermissionCodes().some(
    c => c.localeCompare(target, undefined, { sensitivity: 'accent' }) === 0,
  );
}
